INSERT INTO public.play_questions (domain, category, content, options, correct_answer_index, explanation)
VALUES
  ('funbrain', 'mental_math', '{"text": "In combinatorics, how many distinct subsets containing exactly 2 elements can be formed from a master set containing 5 distinct elements?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["5", "20", "25", "10"]'::jsonb, 3, 'This asks for combinations, ⁵C₂. Mentally calculate (5 × 4) / (2 × 1) = 20 / 2 = 10.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(3^4 \\pmod 5\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["2", "4", "1", "0"]'::jsonb, 2, 'Calculate 3⁴ = 81. Divide 81 by 5, which gives 80 with a remainder of 1.'),
  ('funbrain', 'mental_math', '{"text": "According to Vieta''s formulas, what is the sum of the roots of the cubic equation \\(x^3 - 6x^2 + 11x - 6 = 0\\)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["11", "3", "−6", "6"]'::jsonb, 3, 'The sum of the roots of any polynomial is always −b/a. Here, −(−6)/1 = 6.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\log_2(64) - \\log_3(27)\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["9", "0", "3", "1"]'::jsonb, 2, 'log₂(64) = 6; log₃(27) = 3; therefore 6 − 3 = 3.'),
  ('funbrain', 'mental_math', '{"text": "What is the total number of terms in the completely expanded binomial expression of \\((x + y)^{15}\\)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["15", "14", "256", "16"]'::jsonb, 3, 'The expansion of (a+b)ⁿ always yields exactly n + 1 terms.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(|3 - 4i|^2\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["5", "34", "7", "25"]'::jsonb, 3, 'The modulus squared is a² + b² = 9 + 16 = 25.'),
  ('funbrain', 'mental_math', '{"text": "If Set A and Set B are mutually disjoint, what is P(A ∩ B)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["P(A)P(B)", "1", "0", "P(A) + P(B)"]'::jsonb, 2, 'Disjoint sets share no common elements; intersection is empty (impossible event).'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(2^{10} \\div 2^7\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["4", "128", "8", "16"]'::jsonb, 2, 'Subtract exponents: 10 − 7 = 3; 2³ = 8.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(i^{2024} + i^{2025}\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["\\(1 + i\\)", "\\(1 - i\\)", "\\(0\\)", "\\(-1 + i\\)"]'::jsonb, 0, '2024 is a multiple of 4, so i²⁰²⁴ = 1; i²⁰²⁵ = i.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(5! \\div 3!\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["10", "15", "20", "60"]'::jsonb, 2, '5! / 3! = 5 × 4 = 20 after cancelling 3!.'),
  ('funbrain', 'mental_math', '{"text": "What is the absolute maximum value of \\(3\\sin(x) - 4\\cos(x)\\)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1", "7", "25", "5"]'::jsonb, 3, 'Maximum of a sin x + b cos x is √(a² + b²) = √(9+16) = 5.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\sin(15^\\circ)\\cos(15^\\circ)\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["0", "√3/4", "1/2", "\\(1/4\\)"]'::jsonb, 3, 'Use 2 sin θ cos θ = sin 2θ: value is sin(30°)/2 = 1/4.'),
  ('funbrain', 'mental_math', '{"text": "How many real solutions does \\(\\sin(x) = 2\\) have in \\([0, 2\\pi]\\)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["∞", "1", "0", "2"]'::jsonb, 2, 'Range of sine is [−1, 1]; it can never equal 2.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\tan(1^\\circ)\\tan(89^\\circ)\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["−1", "2", "0", "1"]'::jsonb, 3, 'tan(89°) = cot(1°); product of tan and cot of same angle is 1.'),
  ('funbrain', 'mental_math', '{"text": "What is the fundamental period of \\(f(x) = \\sin(3x)\\)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["\\(2\\pi/3\\)", "\\(2\\pi\\)", "\\(3\\pi\\)", "\\(\\pi/3\\)"]'::jsonb, 0, 'Period of sin(kx) is 2π/k.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\cos^2(\\pi/8) - \\sin^2(\\pi/8)\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1/2", "\\(\\sqrt{2}/2\\)", "0", "1"]'::jsonb, 1, 'This is cos(π/4) = 1/√2 = √2/2.'),
  ('funbrain', 'mental_math', '{"text": "What is the principal value of \\(\\arcsin(-\\sqrt{3}/2)\\) in radians?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["\\(\\pi/3\\)", "\\(\\pi/6\\)", "\\(-\\pi/6\\)", "\\(-\\pi/3\\)"]'::jsonb, 3, 'Principal range [−π/2, π/2]; sin(−π/3) = −√3/2.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(2\\sin(75^\\circ)\\cos(75^\\circ)\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1", "0", "1/2", "√3/2"]'::jsonb, 2, 'Equals sin(150°) = 1/2.'),
  ('funbrain', 'mental_math', '{"text": "In triangle ABC with sides a=3, b=4, c=5, what is cos(C)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["4/5", "3/5", "1", "0"]'::jsonb, 3, '3-4-5 right triangle; angle C is 90°; cos 90° = 0.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\sec^2(45^\\circ) + \\csc^2(45^\\circ)\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["4", "2", "8", "1"]'::jsonb, 0, 'sec 45° = csc 45° = √2; each square is 2; sum = 4.'),
  ('funbrain', 'mental_math', '{"text": "What is the geometric mean of 4 and 36?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["12", "9", "18", "20"]'::jsonb, 0, '√(4×36) = √144 = 12.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\sum_{k=1}^5 (2k - 1)\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["25", "20", "36", "15"]'::jsonb, 0, 'Sum of first n odd numbers is n²; here n=5 → 25.'),
  ('funbrain', 'mental_math', '{"text": "What is the 5th term of a GP with first term 2 and common ratio −2?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["−32", "64", "16", "32"]'::jsonb, 3, 'ar⁴ = 2(−2)⁴ = 2×16 = 32.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate the infinite sum \\(1 - 1/2 + 1/4 - 1/8 + \\cdots\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1/2", "4/3", "2/3", "1"]'::jsonb, 2, 'Geometric series a=1, r=−1/2; sum = 1/(1−r) = 2/3.'),
  ('funbrain', 'mental_math', '{"text": "The sum of the first n natural numbers is 55. Find n.", "pack": "cbse_mental_math_puc100"}'::jsonb, '["9", "10", "11", "12"]'::jsonb, 1, 'n(n+1)/2 = 55 ⇒ n(n+1)=110 ⇒ n=10.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\((1+2+3)^2 - (1^2+2^2+3^2)\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["14", "0", "22", "36"]'::jsonb, 2, '6² − (1+4+9) = 36 − 14 = 22.'),
  ('funbrain', 'mental_math', '{"text": "What is the arithmetic mean of the roots of x² − 10x + 21 = 0?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["3", "21/2", "10", "5"]'::jsonb, 3, 'Sum of roots = 10; mean of two roots = 10/2 = 5.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(1000^{1/3} \\times 16^{1/4}\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["12", "8", "20", "40"]'::jsonb, 2, '10 × 2 = 20.'),
  ('funbrain', 'mental_math', '{"text": "How many positive three-digit integers are divisible by 5?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["90", "179", "180", "200"]'::jsonb, 2, 'From 100 to 995 step 5: (995−100)/5 + 1 = 180.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(^5C_2 \\times {}^3C_1\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["30", "15", "20", "60"]'::jsonb, 0, '10 × 3 = 30.'),
  ('funbrain', 'mental_math', '{"text": "Tangent to y = x³ at x = −1 has slope 3. What is the slope of the normal at that point?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["−3", "−1/3", "1/3", "3"]'::jsonb, 1, 'Normal slope is negative reciprocal of tangent slope.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\lim_{x \\to 2} \\dfrac{x^2 - 4}{x - 2}\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["4", "∞", "2", "0"]'::jsonb, 0, '0/0 form; simplify to x+2 or L''Hôpital → 2x at 2 → 4.'),
  ('funbrain', 'mental_math', '{"text": "What is \\(\\dfrac{d}{d(e^x)}(e^{2x})\\) (derivative of \\(e^{2x}\\) w.r.t. \\(e^x\\))?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["\\(2e^x\\)", "\\(2e^{2x}\\)", "\\(e^x\\)", "2"]'::jsonb, 0, 'Chain rule ratio du/dv gives 2e²ˣ/eˣ = 2eˣ.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\dfrac{d}{dx}(\\ln(x^3))\\) at \\(x = e\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["3", "e³", "3/e", "1/e"]'::jsonb, 2, '3/x at x=e gives 3/e.'),
  ('funbrain', 'mental_math', '{"text": "x-coordinate of inflection of f(x) = x³ − 3x²?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["0", "2", "1", "−1"]'::jsonb, 2, 'f''''(x) = 6x − 6 = 0 ⇒ x = 1.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\lim_{x \\to \\infty} \\dfrac{2x^2 + 3}{5x^2 - 1}\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["5/2", "0", "1", "2/5"]'::jsonb, 3, 'Ratio of leading coefficients.'),
  ('funbrain', 'mental_math', '{"text": "If y = sin(x), what is the 2026th derivative of y w.r.t. x?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["\\(\\sin(x)\\)", "\\(-\\sin(x)\\)", "\\(\\cos(x)\\)", "\\(-\\cos(x)\\)"]'::jsonb, 1, 'Derivatives cycle every 4; 2026 ≡ 2 mod 4 → −sin x.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\dfrac{d}{dx}(x^x)\\) at \\(x = 1\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1", "e", "0", "2"]'::jsonb, 0, 'xˣ(1 + ln x) at 1 gives 1.'),
  ('funbrain', 'mental_math', '{"text": "Minimum value of x² + 1/x² for real non-zero x (AM–GM)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1", "2", "0", "4"]'::jsonb, 1, 'AM–GM gives (x² + 1/x²)/2 ≥ 1 ⇒ minimum sum 2.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\lim_{x \\to 0} \\dfrac{1 - \\cos 2x}{x^2}\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["0", "1", "4", "2"]'::jsonb, 3, '1 − cos 2x = 2 sin²x; limit 2(sin x/x)² = 2.'),
  ('funbrain', 'mental_math', '{"text": "Definite integral of an odd continuous function from −a to a?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["undefined", "2a", "0", "1"]'::jsonb, 2, 'Symmetric limits cancel areas.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\int_0^{\\pi/4} \\sec^2 x \\, dx\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["√2", "0", "1", "2"]'::jsonb, 2, 'tan x from 0 to π/4 = 1 − 0 = 1.'),
  ('funbrain', 'mental_math', '{"text": "Geometric area under y = sin x from 0 to π (above x-axis)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["π", "0", "1", "2"]'::jsonb, 3, '∫₀^π sin x dx = 2.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\int_0^1 x e^{x^2} \\, dx\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1/2", "(e − 1)/2", "e/2", "e − 1"]'::jsonb, 1, 'u = x²; integral (1/2)(e − 1).'),
  ('funbrain', 'mental_math', '{"text": "Integrating factor for \\(dy/dx + (1/x)y = x^2\\)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1/x", "x", "eˣ", "x²"]'::jsonb, 1, 'IF = e^{∫(1/x)dx} = e^{ln x} = x.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\int_1^2 (3x^2 - 2x) \\, dx\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["5", "4", "2", "3"]'::jsonb, 1, 'Antiderivative x³ − x²; (8−4)−(1−1)=4.'),
  ('funbrain', 'mental_math', '{"text": "Order of the differential equation y'''' = √(1 + (y'')³)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["0", "1", "3", "2"]'::jsonb, 3, 'Highest derivative is y''''.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\int_{-1}^1 |x| \\, dx\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["2", "0", "1", "1/2"]'::jsonb, 2, 'Two triangles area 1/2 each → total 1.'),
  ('funbrain', 'mental_math', '{"text": "General solution of dy/dx = y/x?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["y = 0", "y = cx", "y = x²", "y = eˣ"]'::jsonb, 1, 'Separate and integrate → y proportional to x.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\int_0^{\\infty} e^{-x} \\, dx\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["0", "∞", "e", "1"]'::jsonb, 3, 'Improper integral of e^{−x} from 0 to ∞ = 1.'),
  ('funbrain', 'mental_math', '{"text": "Determinant of a skew-symmetric matrix of odd order (e.g. 3×3)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["undefined", "1", "−1", "0"]'::jsonb, 3, 'Odd-order skew-symmetric matrices have determinant 0.'),
  ('funbrain', 'mental_math', '{"text": "Determinant of 3I₃ (3×3 scalar multiple of identity)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["9", "81", "3", "27"]'::jsonb, 3, 'Product of diagonal: 3³ = 27.'),
  ('funbrain', 'mental_math', '{"text": "If A and B are symmetric matrices of same order, when is AB symmetric?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["If AB = BA (they commute)", "If A = B", "Never", "Always"]'::jsonb, 0, '(AB)ᵀ = BᵀAᵀ = BA; need BA = AB.'),
  ('funbrain', 'mental_math', '{"text": "Trace of \\(A = \\begin{bmatrix}2 & -1\\\\ 4 & 5\\end{bmatrix}\\)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["7", "10", "−3", "6"]'::jsonb, 0, 'Sum of diagonal: 2 + 5 = 7.'),
  ('funbrain', 'mental_math', '{"text": "Relationship between |A| and |A⁻¹| for non-singular A?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["|A⁻¹| = 0", "|A⁻¹| = 1/|A|", "|A⁻¹| = −|A|", "|A⁻¹| = |A|"]'::jsonb, 1, '|A||A⁻¹| = |I| = 1.'),
  ('funbrain', 'mental_math', '{"text": "If |A| = 5 for 2×2 A, evaluate |2A|.", "pack": "cbse_mental_math_puc100"}'::jsonb, '["20", "25", "10", "40"]'::jsonb, 0, '|kA| = kⁿ|A| with n=2 → 4×5 = 20.'),
  ('funbrain', 'mental_math', '{"text": "Maximum number of distinct 2×2 matrices with entries only 0 or 1?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["16", "8", "32", "4"]'::jsonb, 0, '2⁴ = 16 choices for four entries.'),
  ('funbrain', 'mental_math', '{"text": "If \\(|A| = 4\\) for invertible 3×3 A, find \\(|adj(A)|\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["4", "64", "12", "16"]'::jsonb, 3, '|adj A| = |A|ⁿ⁻¹ = 4² = 16.'),
  ('funbrain', 'mental_math', '{"text": "A square matrix is orthogonal if AAᵀ equals?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["A", "2I", "Zero matrix", "The identity matrix I"]'::jsonb, 3, 'Orthogonal: Aᵀ = A⁻¹ ⇒ AAᵀ = I.'),
  ('funbrain', 'mental_math', '{"text": "Rank of 2×2 matrix with rows [2,4] and [4,8]?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["−1", "1", "0", "2"]'::jsonb, 1, 'Rows are dependent; one independent row.'),
  ('funbrain', 'mental_math', '{"text": "Geometric meaning of |a · (b × c)|?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["Area of triangle", "Length of a", "Dot product", "Volume of a parallelepiped"]'::jsonb, 3, 'Scalar triple product magnitude is parallelotope volume.'),
  ('funbrain', 'mental_math', '{"text": "Evaluate \\(\\hat{i} \\cdot (\\hat{j} \\times \\hat{k}) + \\hat{j} \\cdot (\\hat{i} \\times \\hat{k})\\).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["−2", "2", "0", "1"]'::jsonb, 2, '1 + (−1) = 0.'),
  ('funbrain', 'mental_math', '{"text": "Locus of points satisfying \\(x^2 + y^2 + z^2 = 0\\) in ℝ³?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["A sphere", "A plane", "The origin (0, 0, 0)", "A line"]'::jsonb, 2, 'Sum of squares zero ⇒ each coordinate 0.'),
  ('funbrain', 'mental_math', '{"text": "Perpendicular distance from (3,4,5) to the y-axis?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["√34", "5", "√50", "7"]'::jsonb, 0, '√(x²+z²) = √(9+25) = √34.'),
  ('funbrain', 'mental_math', '{"text": "Direction cosines of a line equally inclined to all three axes?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1, 1, 1", "±1/√3, ±1/√3, ±1/√3", "1/2, 1/2, 1/√2", "1, 0, 0"]'::jsonb, 1, '3 cos²θ = 1 ⇒ cos θ = ±1/√3.'),
  ('funbrain', 'mental_math', '{"text": "Scalar projection of A = 2i − j + k onto B = i + 2j − 2k?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["0", "2/3", "−2/3", "−2"]'::jsonb, 2, '(A·B)/|B| = −2/3.'),
  ('funbrain', 'mental_math', '{"text": "Maximum number of mutually perpendicular unit vectors in ℝ³?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["2", "4", "3", "∞"]'::jsonb, 2, 'Dimension of space.'),
  ('funbrain', 'mental_math', '{"text": "Dot product of two distinct unit vectors at 60°?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1", "0", "√3/2", "1/2"]'::jsonb, 3, 'cos 60° = 1/2.'),
  ('funbrain', 'mental_math', '{"text": "Four points are coplanar if scalar triple product of three edge vectors equals?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["0", "undefined", "1", "−1"]'::jsonb, 0, 'Zero volume ⇒ coplanar.'),
  ('funbrain', 'mental_math', '{"text": "Area of parallelogram with adjacent sides 3i and 4j?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["7", "12", "24", "0"]'::jsonb, 1, '|3i × 4j| = 12.'),
  ('funbrain', 'mental_math', '{"text": "If A and B are independent, P(A|B) equals?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["P(A∩B)", "P(B)", "0", "P(A)"]'::jsonb, 3, 'Conditioning gives no new information.'),
  ('funbrain', 'mental_math', '{"text": "Variance of Binomial(n=10, p=0.5)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["5", "10", "2.5", "2"]'::jsonb, 2, 'npq = 10×0.5×0.5 = 2.5.'),
  ('funbrain', 'mental_math', '{"text": "Bayes: initial probability before evidence is called?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["Likelihood", "Marginal", "Prior probability", "Posterior"]'::jsonb, 2, 'Updated value is posterior.'),
  ('funbrain', 'mental_math', '{"text": "Fair coin tossed 3 times: probability of exactly two heads?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["1/4", "3/8", "3/4", "1/2"]'::jsonb, 1, '3 favorable outcomes out of 8.'),
  ('funbrain', 'mental_math', '{"text": "A numerical outcome of a random experiment is modeled as a?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["Distribution", "Random variable", "Sample space", "Event"]'::jsonb, 1, 'Maps outcomes to real numbers.'),
  ('funbrain', 'mental_math', '{"text": "P(A)=0.6, P(B)=0.5, P(A∪B)=0.8. Find P(A∩B).", "pack": "cbse_mental_math_puc100"}'::jsonb, '["0.4", "0.8", "0.1", "0.3"]'::jsonb, 3, '0.6+0.5−x=0.8 ⇒ x=0.3.'),
  ('funbrain', 'mental_math', '{"text": "Sum of probabilities over all outcomes of a discrete random variable?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["0", "∞", "100", "1"]'::jsonb, 3, 'Total probability is 100%.'),
  ('funbrain', 'mental_math', '{"text": "Expected value of one roll of a fair six-sided die?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["3", "4", "21", "3.5"]'::jsonb, 3, '(1+2+3+4+5+6)/6 = 21/6 = 3.5.'),
  ('funbrain', 'mental_math', '{"text": "If E and F are mutually exclusive, P(E ∩ F)?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["0", "P(E)P(F)", "1", "P(E)+P(F)"]'::jsonb, 0, 'Cannot occur together.'),
  ('funbrain', 'mental_math', '{"text": "Probability a random leap year has exactly 53 Sundays?", "pack": "cbse_mental_math_puc100"}'::jsonb, '["3/7", "2/7", "1/2", "1/7"]'::jsonb, 1, '366 = 52 weeks + 2 days; 2 of 7 weekday pairs include Sunday.'),
